UPDATE Letture_Acqua_Semestrali SET Utente = concat(new.Nome, ' ',new.Cognome), Internus = new.Interno WHERE
Utente = concat(old.Nome, ' ', old.Cognome) and Internus = old.Interno and  ID = old.ID_Condominio;

