Arrotondamenti.Utente = concat(old.Nome, ' ', old.Cognome) and Internio = old.Interno and  Arrotondamenti.ID_Condominio = old.ID_Condominio;

UPDATE Contabilita_Chiuse set Utente =  concat(new.Nome,' ',new.Cognome), 
Interno = new.Interno 
WHERE
Utente = concat(old.Nome,' ', old.Cognome) and Interno = old.Interno and  Contabilita_Chiuse.ID_Condominio = old.ID_Condominio;


