WHERE
Utente = concat(old.Nome, ' ', old.Cognome) and Interno = old.Interno and  Richieste_Accettazioni.ID_Condominio = old.ID_Condominio;

UPDATE Letture_Acqua_Mensili SET Utente = concat(new.Nome, ' ',new.Cognome), Internus = new.Interno WHERE
Utente = concat(old.Nome, ' ', old.Cognome) and Internus = old.Interno and  ID = old.ID_Condominio;

UPDATE Medie_Imposte SET Utente = concat(new.Nome, ' ',new.Cognome), Medie_Imposte.Interno = new.Interno WHERE
Utente = concat(old.Nome, ' ', old.Cognome) and Medie_Imposte.Interno = old.Interno and  Medie_Imposte.ID_Condominio = old.ID_Condominio;

